-- W1.6 questions batch 7482/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-b20a8cf8-moex-00324', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '下列有關文書鑑定及處理相關之敘述，何者最不適當？', '["用相同顏色但不同廠牌之墨水進行竄改字跡，就難以鑑定竄改情形", "筆跡鑑定具有類化特徵與個化特徵，一般而言，類化特徵比個化特徵容易複製", "筆跡鑑定時，標準字跡與當庭書寫字跡應儘可能收集", "使用靜電壓痕偵測儀（ESDA）可以用來顯現壓痕字跡，有時候也可以同時顯現出潛伏指紋"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "3693ce52aabf", "answer_pdf_sha1": "1758385edbdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00325', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '以多波域光源檢視現場可疑跡證，發現其吸收波長介於490-510 nm之間，該物螢光發射波長介 於640-660 nm之間，請問欲拍攝該證物螢光影像時應使用下列何種濾鏡，可獲得最佳證物螢光 影像效果？', '["黃色濾鏡", "橘色濾鏡", "紅色濾鏡", "透明濾鏡"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "3693ce52aabf", "answer_pdf_sha1": "1758385edbdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00326', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '現場勘察人員可以從現場血跡特殊型態，研判案情，以獲得正確偵查方向，下列敘述何者錯誤？', '["在血跡型態的分析中，消失的血跡型態與出現的血跡型態是同等重要", "拋甩（Cast-off）的血跡型態可研判對於血液來源揮擊的次數", "現場的血灘（Poolingofblood）可以提供血液流出的量與受傷種類的資訊", "在高速度撞擊（例如：子彈等）的血液噴濺痕中，只有前噴（Forwardspatter）血跡有散射效應 （Dispersioneffects），而後噴（Backspatter）血跡則無散射效應"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "3693ce52aabf", "answer_pdf_sha1": "1758385edbdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00327', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '顯微鏡是刑事實驗室不可缺少的基本儀器設備之一，鑑識人員必須熟悉該項設備之操作。有關顯 微鏡基本知識下列敘述何者錯誤？', '["凡屬平行光線經過透鏡後會在平面上的一點聚集，這個聚集點稱焦點，這個平面稱焦平面", "波長較長的光線折射較大，波長較短則折射較小，這種現象稱為色像偏差（Chromaticaberration）", "鏡面的球形彎曲度愈大通過光線折射愈大，這種現象稱為球形偏差（Sphericalaberration）", "當光源波長固定時，NA值（Numericalaperture）愈大，則鏡頭解析能力愈高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "3693ce52aabf", "answer_pdf_sha1": "1758385edbdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00328', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'essay', '請試述警察偵查犯罪手冊中對犯罪被害人保護的作法；另再舉出一項作
法說明警察針對性侵害被害人的特別保護措施。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00329', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'essay', '刑案區分為普通刑案、重大刑案及特殊刑案，請試述「特殊刑案」的定
義？以及依據警察偵查犯罪手冊有關特殊刑案之偵查責任區分與督導
管理規範為何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00330', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '偵查犯罪，應遵守偵查不公開之原則，但依法令經審酌公共利益之維護或合法權益之保護，於認 有必要時得適度公開或揭露偵查程序或偵查內容。試問，有關本項偵查不公開原則的說明，以下 敘述何者正確？', '["對於社會治安有重大影響或社會矚目案件，偵辦人員可不經去識別化自行公開偵查之照片或物品", "對於媒體報導與事實不符，影響訴訟關係人之名譽、隱私等，偵辦人員認有澄清必要可公開偵 查之影音資料", "對於影響社會大眾生命、身體安全之案件，警察機關認有告知民眾注意防範之必要，可以公開 犯罪嫌疑人之前科資料", "對於現時難以調查證據之案件，警察機關審酌犯罪嫌疑人行使防禦權之必要，為請大眾提供證 據可以公開其前科資料"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00331', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '某甲行經某處發現有人倒臥血泊旋即向派出所報案，警察乙到達犯罪現場進行蒐證，發現路邊有 監視器拍攝到模糊人像。警察局認犯罪情節重大，乃公布影帶懸賞10萬元請民眾協尋影像之人。 某丙見報導前往提供協尋線索。稍後，人犯 A 為領取獎金，委託友人丁前往代為表明其為影中 人，現警察綜合各項蒐證鎖定辦案對象。有關警察機關受理該案，以下敘述何者正確？', '["甲已先行向派出所報案，A不能該當自首", "乙已到過現場蒐證，A不能該當自首", "丙提供辦案線索給予警察局，A不能該當自首", "丁受託報案乃為領取獎金，A不能該當自首"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00332', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '警察為防止危害或犯罪，認對公共安全、公共秩序或個人生命、身體、自由、名譽或財產，將有 危害行為，或有觸犯刑事法律之虞者，得遴選第三人秘密蒐集特定之情報資料。試問警察辦理本 項偵防工作，以下敘述何者正確？', '["第三人遴選及其運用，乃出於其志願與警察合作故不可支給費用或報酬", "第三人遴選及其運用，為確保情報資料之正確，可授予非強制性之警察職權", "第三人遴選及其運用，其所蒐集卷證資料不提供律師或辯護人調閱", "第三人遴選及其運用，其所蒐集之卷證資料並不適用證人保護法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00333', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '警察為查緝某走私毒品犯罪，於犯罪嫌疑人停放公有停車場之自用車裝設衛星定位追蹤器 （GlobalPositioningSystem），接收其所在位置之經緯度、地址及停留時間等數據，用以掌握其 移動行蹤以及毒品交易可能對象。試問，有關本項科技偵查之法定程序，依照實務判決以下說明 何者正確？', '["裝設衛星定位追蹤器等同警察跟蹤監視（警察偵查犯罪手冊第91點）", "裝設衛星定位追蹤器準用警察科技跟監（警察職權行使法第11條）", "裝設衛星定位追蹤器應遵守法律保留（刑事訴訟法第1條）", "裝設衛星定位追蹤器可準用搜索票規定（刑事訴訟法第128條）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
